-- =====================================================================
-- 20260630000300_crossfill_corpora_by_number.sql
-- Corpora / Kazemi tarot dataset (CC0, public domain)
-- Source: github.com/dariusk/corpora  data/divination/tarot_interpretations.json
-- Fills: meaning_light, meaning_shadow, fortune_telling, corpora_keywords
-- Keyed on card_number (0-77). Idempotent: re-running overwrites same 4 cols.
-- Replaces the earlier name-keyed crossfill, which silently skipped cards
-- whose names did not match (e.g. 'The Wheel' vs 'Wheel of Fortune').
-- =====================================================================

alter table tarot_cards add column if not exists meaning_light text[];
alter table tarot_cards add column if not exists meaning_shadow text[];
alter table tarot_cards add column if not exists fortune_telling text[];
alter table tarot_cards add column if not exists corpora_keywords text[];

begin;
update tarot_cards set meaning_light='{"Freeing yourself from limitation","Expressing joy and youthful vigor","Being open-minded","Taking a leap of faith","Attuning yourself to your instincts","Being eager or curious","Exploring your potential","Embracing innovation and change"}', meaning_shadow='{"Being gullible and naive","Taking unnecessary risks","Failing to be serious when required","Being silly or distracted","Lacking experience","Failing to honor well-established traditions and limits","Behaving inappropriately"}', fortune_telling='{"Watch for new projects and new beginnings","Prepare to take something on faith","Something new comes your way; go for it"}', corpora_keywords='{"freedom","faith","inexperience","innocence"}' where card_number=0;
